def solve(self, a: list[int]) -> bool:
    if len(a) == 1:
        return False
    res = []
    st = []
    st.append(a[0])
    for i in range(1, len(a)):
        if a[i] > a[i-1]:
            st.append(a[i])
        elif i > 1 and a[i] < a[i-1] and a[i] < a[i-2]:
            res.append(i-1)
    return str(res).replace('[', '').replace(']', '')


