#include<iostream>
#include<vector>
#include<stack>
using namespace std;
class Solution {
public:
bool solve(vector<int>& a){
    bool res = false;
    stack<int> st;
    st.push(a[0]);
    for (int i = 1; i < a.size(); i++) {
        if (a[i] > a[i-1])
            st.push(a[i]);
        else if (i > 1 && a[i] < a[i-1] && a[i] < a[i-2])
            res = true;
    }
    return res;
}
};
